package com.example.yourapp

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.util.Log
import android.view.View
import android.widget.ImageView
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity

class ShareHandlerActivity : AppCompatActivity() {

    private lateinit var sharedContentTextView: TextView
    private lateinit var sharedContentImageView: ImageView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share_handler)

        sharedContentTextView = findViewById(R.id.sharedContentTextView)
        sharedContentImageView = findViewById(R.id.sharedContentImageView)

        when (intent?.action) {
            Intent.ACTION_SEND -> {
                if (intent.type != null) {
                    handleSingleShare(intent)
                }
            }
            Intent.ACTION_SEND_MULTIPLE -> {
                if (intent.type != null) {
                    handleMultipleShare(intent)
                }
            }
            else -> {
                sharedContentTextView.text = "No recognizable share intent received."
                Log.d("ShareHandlerActivity", "Unhandled intent action: ${intent?.action}")
            }
        }
    }

    private fun handleSingleShare(intent: Intent) {
        when {
            intent.type?.startsWith("text/") == true -> {
                val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                if (!sharedText.isNullOrBlank()) {
                    sharedContentTextView.text = "Shared Text/URL:\n$sharedText"
                    Log.d("ShareHandlerActivity", "Received single text/URL: $sharedText")
                } else {
                    sharedContentTextView.text = "Received empty text share."
                }
            }
            intent.type?.startsWith("image/") == true -> {
                val imageUri: Uri? = intent.getParcelableExtra(Intent.EXTRA_STREAM)
                if (imageUri != null) {
                    displayImage(imageUri)
                    sharedContentTextView.text = "Shared Image: ${imageUri.lastPathSegment ?: imageUri.toString()}"
                    Log.d("ShareHandlerActivity", "Received single image URI: $imageUri")
                } else {
                    sharedContentTextView.text = "Received image share but no URI found."
                }
            }
            else -> {
                sharedContentTextView.text = "Received single share of unknown type: ${intent.type}"
                Log.d("ShareHandlerActivity", "Received single share of unknown type: ${intent.type}")
            }
        }
    }

    private fun handleMultipleShare(intent: Intent) {
        val imageUris: ArrayList<Uri>? = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM)
        val textBuilder = StringBuilder("Shared Multiple Items:\n")

        if (imageUris != null && imageUris.isNotEmpty()) {
            textBuilder.append("Type: ${intent.type}\n")
            textBuilder.append("Images (${imageUris.size}):\n")
            
            // For simplicity, display the first image and list all URIs.
            // In a production app, you might use a RecyclerView to display all images.
            displayImage(imageUris[0]) 

            imageUris.forEachIndexed { index, uri ->
                textBuilder.append("  ${index + 1}. ${uri.lastPathSegment ?: uri.toString()}\n")
                Log.d("ShareHandlerActivity", "Received multiple image URI[$index]: $uri")
            }
        } else {
            textBuilder.append("No images found in multiple share (Type: ${intent.type}).")
            Log.d("ShareHandlerActivity", "Received multiple share but no image URIs found.")
        }
        sharedContentTextView.text = textBuilder.toString()
    }

    private fun displayImage(imageUri: Uri) {
        try {
            // The sending app usually grants temporary read permission via the Intent.FLAG_GRANT_READ_URI_PERMISSION flag.
            // Direct use with setImageURI or ContentResolver.openInputStream should work.
            sharedContentImageView.setImageURI(imageUri)
            sharedContentImageView.visibility = View.VISIBLE
            Log.d("ShareHandlerActivity", "Successfully set image URI: $imageUri")
        } catch (e: SecurityException) {
            Log.e("ShareHandlerActivity", "SecurityException: Permission denied for URI: $imageUri", e)
            sharedContentTextView.append("\nError loading image: Permission denied.")
            sharedContentImageView.visibility = View.GONE
        } catch (e: Exception) {
            Log.e("ShareHandlerActivity", "Error setting image URI: $imageUri", e)
            sharedContentTextView.append("\nError loading image: ${e.message}")
            sharedContentImageView.visibility = View.GONE
        }
    }
}

